using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load raw data with the Label as text, then map Yes/No → bool
IDataView rawData = mlContext.Data.LoadFromTextFile<ChurnInputRaw>(
    dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label",
        new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
        inputColumnName: "LabelText")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);
var model = pipeline.Fit(split.TrainSet);

// Evaluate and log metrics
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model to disk
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, rawData.Schema, modelPath);

// Register pooled prediction engine (thread-safe)
builder.Services.AddPredictionEnginePool<ChurnInputRaw, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "ChurnPredictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<ChurnInputRaw, ChurnPrediction> pool, ChurnRequest req) =>
{
    var input = new ChurnInputRaw
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
        LabelText = string.Empty
    };

    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        Churned = prediction.Churned,
        Probability = prediction.Probability
    });
});

app.Run();

// --- Supporting types ---

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

